#define int long long

#define _rep(i,a,b) for (int i=(a);i<=(b);++i)
#define _riter(i,a) for (auto i=a.rbegin();i!=a.rend();++i)

namespace Math {
    const int N=1000005;
    const int mod=998244353;

    int exgcd(int a,int b,int& x,int& y) {
        if (!b) {
            x=1,y=0;
            return a;
        }
        int d=exgcd(b,a%b,y,x);
        y-=a/b*x;
        return d;
    }

    int inverse(int a) {
        int x,y;
        exgcd(a,mod,x,y);
        x=(x%mod+mod)%mod;
        return x;
    }

    int f[N],g[N];

    void init_fact() {
        f[0]=g[0]=1;
        _rep(i,1,N-1) f[i]=f[i-1]*i%mod,g[i]=inverse(f[i]);
    }

    int C(int n,int m) {
        return (f[n]*g[m]%mod)*g[n-m]%mod;
    }

    int A(int n,int m) {
        return f[n]*g[n-m]%mod;
    }
}

namespace Tree {
    const int N=1000005;
    const int M=2000005;
    const int K=1;
    const int mod=998244353;

    int n,m;
    int e[M],ne[M],w[M],h[N],tot;

    void add(int a,int b) {
        e[tot]=b,ne[tot]=h[a],h[a]=tot++;
    }

    void add(int a,int b,int c) {
        e[tot]=b,w[tot]=c,ne[tot]=h[a],h[a]=tot++;
    }
}

using namespace Tree;
using Math::f;
using Math::init_fact;
using Math::A;
using Math::C;

int k,ans;
int dep[N];
int mxdep[N];
vector<int> vec[N];
map<int,int> nums;

void dfs(int u,int fa,int d) {
    dep[u]=mxdep[u]=d;
    vec[d].emplace_back(u);
    _graph(i,u) {
        if (e[i]==fa) continue;
        dfs(e[i],u,d+1);
        mxdep[u]=max(mxdep[u],mxdep[e[i]]);
    }
}

i32 main() {
    // FRR("divide/divide6.in");
    // FRW("divide/my.out");
    memset(h,-1,sizeof(h));
    init_fact();
    read(n),read(k);
    _rep(i,2,n) {
        int p;
        read(p);
        add(p,i),add(i,p);
    }
    dfs(1,0,1);
    // int debug=0;
    _rep(d,2,mxdep[1]) {
        if (vec[d].size()<=k) continue;
        nums.clear();
        _rep(i,0,(int)vec[d].size()-1) nums[mxdep[vec[d][i]]]++;
        int cur=0;
        _riter(it,nums) {
            int dep=it->first,cnt=it->second;
            // cerr<<d<<" "<<dep<<" "<<cnt<<endl;
            // debug=(debug+A(cnt,k))%mod;
            // _assert(cnt==vec[d].size());
            if (cur+cnt<=k) {
                cur+=cnt;
                continue;
            }
            if (cur==k-1 && cnt>1) {
                int res=A(cnt,1)*A(cur,k-1)%mod;
                ans=(ans+res)%mod;
            }
            if (cnt>=2) _rep(i,2,min(cnt,k)) if (cur>=k-i) {
                int res=cnt*C(cnt-1,i-1)%mod;
                res=res*C(cur,k-i)%mod;
                res=res*f[k-1]%mod;
                ans=(ans+res)%mod;
            }
            cur+=cnt;
        }
        // cerr<<"now: "<<d<<" "<<ans<<" "<<debug<<endl;
    }
    // TIMESTAMP
    write(ans);
    return 0;
}
