                    if (mid<x) u=(u<<1|1);
                    else {
                        if (seg.tr[u<<1].v.ep<=y+1) u=(u<<1|1);
                        else u<<=1;
                    }
                }
                int pos=seg.tr[u].l;
                if (seg.tr[u].v.ep<=y+1) pos++;
                pos--;
