    Graph::init_graph();
    read(n,q);
    _rep(i,1,n) read(col[i]);
    _rep(i,1,n) read(d[i]);
    _rep(i,2,n) {
        int fa;
        read(fa);
        add(fa,i),add(i,fa);
    }
    _rep(i,1,500000) las[i]=n+i;
